arguments.file_text:
namespace CourseCatalog.Models;

public class Department
{
    public string Id { get; set; } = string.Empty;
    public string Name { get; set; } = string.Empty;
    public string Abbreviation { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

namespace CourseCatalog.Models;

public class Course
{
    public string Id { get; set; } = string.Empty;
    public string DepartmentId { get; set; } = string.Empty;
    public string CourseNumber { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public string InstructorName { get; set; } = string.Empty;
    public string InstructorBio { get; set; } = string.Empty;
    public bool IsFeatured { get; set; }
}

using System.ComponentModel.DataAnnotations;

namespace CourseCatalog.Models;

public class EnrollmentRequest
{
    [Required(ErrorMessage = "Full name is required.")]
    [StringLength(100, ErrorMessage = "Name must be 100 characters or fewer.")]
    public string FullName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Student ID is required.")]
    [RegularExpression(@"^[A-Za-z0-9\-]+$", ErrorMessage = "Student ID must contain only letters, numbers, and hyphens.")]
    public string StudentId { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please select a course.")]
    public string CourseId { get; set; } = string.Empty;
}

using CourseCatalog.Models;

namespace CourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = "cs", Name = "Computer Science", Abbreviation = "CS", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = "math", Name = "Mathematics", Abbreviation = "MATH", Description = "Study of numbers, structures, and patterns." },
            new() { Id = "eng", Name = "English", Abbreviation = "ENG", Description = "Study of literature, writing, and language." },
            new() { Id = "phys", Name = "Physics", Abbreviation = "PHYS", Description = "Study of matter, energy, and the fundamental forces of nature." },
            new() { Id = "hist", Name = "History", Abbreviation = "HIST", Description = "Study of past events and civilizations." },
            new() { Id = "bio", Name = "Biology", Abbreviation = "BIO", Description = "Study of living organisms and life processes." },
        };

        _courses = new List<Course>
        {
            // Computer Science
            new() { Id = "cs101", DepartmentId = "cs", CourseNumber = "CS 101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using Python. Topics include variables, control flow, functions, and basic data structures. No prior experience required.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", InstructorName = "Dr. Ada Lovelace", InstructorBio = "Dr. Lovelace has 15 years of experience teaching introductory computer science. Her research focuses on CS education and making programming accessible to all students.", IsFeatured = true },
            new() { Id = "cs201", DepartmentId = "cs", CourseNumber = "CS 201", Title = "Data Structures & Algorithms", Description = "Study fundamental data structures (arrays, linked lists, trees, graphs, hash tables) and algorithm design techniques. Includes analysis of time and space complexity.", Credits = 4, Schedule = "Tue/Thu 10:30 AM–12:00 PM", InstructorName = "Dr. Alan Turing", InstructorBio = "Dr. Turing specializes in algorithm optimization and computational theory. He has published extensively on efficient data processing.", IsFeatured = false },
            new() { Id = "cs310", DepartmentId = "cs", CourseNumber = "CS 310", Title = "Database Systems", Description = "Design and implementation of relational databases. Covers SQL, normalization, indexing, transaction processing, and an introduction to NoSQL systems.", Credits = 3, Schedule = "Mon/Wed 2:00–3:20 PM", InstructorName = "Dr. Edgar Codd", InstructorBio = "Dr. Codd is an expert in database theory and has consulted for major technology companies on large-scale data architecture.", IsFeatured = false },
            new() { Id = "cs420", DepartmentId = "cs", CourseNumber = "CS 420", Title = "Artificial Intelligence", Description = "Survey of AI techniques including search, knowledge representation, machine learning, and neural networks. Includes hands-on projects with real-world datasets.", Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", InstructorName = "Dr. Grace Hopper", InstructorBio = "Dr. Hopper's research spans machine learning and natural language processing. She leads the university's AI research lab.", IsFeatured = true },

            // Mathematics
            new() { Id = "math101", DepartmentId = "math", CourseNumber = "MATH 101", Title = "Calculus I", Description = "Introduction to differential and integral calculus of single-variable functions. Covers limits, derivatives, and basic integration techniques.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", InstructorName = "Dr. Isaac Newton", InstructorBio = "Dr. Newton has been teaching calculus for over 20 years and is known for his clear, intuitive approach to mathematical concepts.", IsFeatured = true },
            new() { Id = "math201", DepartmentId = "math", CourseNumber = "MATH 201", Title = "Linear Algebra", Description = "Study of vector spaces, linear transformations, matrices, determinants, eigenvalues, and eigenvectors with applications.", Credits = 3, Schedule = "Tue/Thu 9:00–10:20 AM", InstructorName = "Dr. Emmy Noether", InstructorBio = "Dr. Noether is a renowned algebraist whose research connects abstract algebra to physics and computer science.", IsFeatured = false },
            new() { Id = "math305", DepartmentId = "math", CourseNumber = "MATH 305", Title = "Probability & Statistics", Description = "Introduction to probability theory, random variables, distributions, hypothesis testing, and regression analysis.", Credits = 3, Schedule = "Mon/Wed 11:00 AM–12:20 PM", InstructorName = "Dr. Carl Gauss", InstructorBio = "Dr. Gauss brings applied statistics experience from industry and academia, specializing in Bayesian methods.", IsFeatured = false },

            // English
            new() { Id = "eng101", DepartmentId = "eng", CourseNumber = "ENG 101", Title = "College Writing", Description = "Develop critical writing skills through essays, research papers, and peer review. Emphasizes argumentation, evidence, and clear prose.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", InstructorName = "Dr. Maya Angelou", InstructorBio = "Dr. Angelou is an award-winning author and writing instructor passionate about helping students find their voice.", IsFeatured = false },
            new() { Id = "eng220", DepartmentId = "eng", CourseNumber = "ENG 220", Title = "American Literature", Description = "Survey of major works in American literature from the colonial period to the present. Examines themes of identity, freedom, and social change.", Credits = 3, Schedule = "Tue/Thu 2:00–3:20 PM", InstructorName = "Dr. Mark Twain", InstructorBio = "Dr. Twain specializes in 19th-century American fiction and has published several books on the evolution of American literary identity.", IsFeatured = true },

            // Physics
            new() { Id = "phys101", DepartmentId = "phys", CourseNumber = "PHYS 101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Includes laboratory sessions. Calculus-based approach for science and engineering students.", Credits = 4, Schedule = "Mon/Wed/Fri 1:00–1:50 PM, Lab: Fri 2:00–4:00 PM", InstructorName = "Dr. Richard Feynman", InstructorBio = "Dr. Feynman is celebrated for his engaging lectures and groundbreaking work in quantum electrodynamics.", IsFeatured = false },
            new() { Id = "phys202", DepartmentId = "phys", CourseNumber = "PHYS 202", Title = "Electromagnetism", Description = "Electric fields, magnetic fields, Maxwell's equations, and electromagnetic waves. Laboratory component included.", Credits = 4, Schedule = "Tue/Thu 10:30 AM–12:00 PM, Lab: Wed 2:00–4:00 PM", InstructorName = "Dr. Marie Curie", InstructorBio = "Dr. Curie's research focuses on experimental physics and she has mentored dozens of graduate students in her career.", IsFeatured = false },

            // History
            new() { Id = "hist101", DepartmentId = "hist", CourseNumber = "HIST 101", Title = "World History to 1500", Description = "Survey of world civilizations from prehistory to the early modern period, covering political, social, and cultural developments.", Credits = 3, Schedule = "Tue/Thu 11:00 AM–12:20 PM", InstructorName = "Dr. Howard Zinn", InstructorBio = "Dr. Zinn brings a social history perspective to his teaching, emphasizing the experiences of ordinary people throughout history.", IsFeatured = false },
            new() { Id = "hist250", DepartmentId = "hist", CourseNumber = "HIST 250", Title = "The Modern World", Description = "Examines global history from 1500 to the present, including colonialism, industrialization, world wars, and globalization.", Credits = 3, Schedule = "Mon/Wed 3:30–4:50 PM", InstructorName = "Dr. Doris Kearns", InstructorBio = "Dr. Kearns is a presidential historian and frequent media commentator on the intersection of politics and history.", IsFeatured = true },

            // Biology
            new() { Id = "bio101", DepartmentId = "bio", CourseNumber = "BIO 101", Title = "Introduction to Biology", Description = "Fundamentals of cell biology, genetics, evolution, and ecology. Includes weekly lab sessions with hands-on experiments.", Credits = 4, Schedule = "Mon/Wed/Fri 8:00–8:50 AM, Lab: Thu 2:00–4:00 PM", InstructorName = "Dr. Charles Darwin", InstructorBio = "Dr. Darwin is a field biologist and evolutionary ecologist who integrates research experiences into undergraduate education.", IsFeatured = false },
            new() { Id = "bio310", DepartmentId = "bio", CourseNumber = "BIO 310", Title = "Molecular Biology", Description = "Structure and function of biological macromolecules, gene expression, DNA replication, and modern techniques in molecular biology.", Credits = 3, Schedule = "Tue/Thu 3:30–4:50 PM", InstructorName = "Dr. Rosalind Franklin", InstructorBio = "Dr. Franklin is an expert in structural biology and X-ray crystallography with active research in protein engineering.", IsFeatured = false },
        };
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(string id) =>
        _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses() => _courses;

    public List<Course> GetFeaturedCourses() =>
        _courses.Where(c => c.IsFeatured).ToList();

    public Course? GetCourse(string id) =>
        _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> SearchCourses(string? searchTerm, string? departmentId)
    {
        var query = _courses.AsEnumerable();

        if (!string.IsNullOrWhiteSpace(departmentId))
        {
            query = query.Where(c => c.DepartmentId == departmentId);
        }

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.CourseNumber.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.OrderBy(c => c.CourseNumber).ToList();
    }
}

namespace CourseCatalog.Models;

public class Department
{
    public string Id { get; set; } = string.Empty;
