        };
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(string id) =>
        _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses() => _courses;

    public List<Course> GetFeaturedCourses() =>
        _courses.Where(c => c.IsFeatured).ToList();

    public Course? GetCourse(string id) =>
        _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> SearchCourses(string? searchTerm, string? departmentId)
    {
        var query = _courses.AsEnumerable();

        if (!string.IsNullOrWhiteSpace(departmentId))
        {
            query = query.Where(c => c.DepartmentId == departmentId);
        }

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.CourseNumber.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.OrderBy(c => c.CourseNumber).ToList();
    }
}

