+    private string selectedDepartment
+    {
+        get => _selectedDepartment ?? string.Empty;
+        set { _selectedDepartment = value; ApplyFilters(); }
+    }
+
+    protected override void OnInitialized()
+    {
+        departments = Catalog.GetDepartments();
+        _selectedDepartment = InitialDepartment;
+        ApplyFilters();
+    }
+
+    private void ApplyFilters()
+    {
+        filteredCourses = Catalog.SearchCourses(searchTerm, selectedDepartment);
