@page "/"
@using CourseCatalog.Models
@using CourseCatalog.Services
@inject CatalogService Catalog

<PageTitle>Home — University Course Catalog</PageTitle>

<h1>University Course Catalog</h1>
<p class="lead">Browse our courses, explore departments, and enroll for the upcoming semester.</p>

<hr />

<h2>Featured Courses</h2>
<div class="row mb-4">
    @foreach (var course in featuredCourses)
    {
        var dept = Catalog.GetDepartment(course.DepartmentId);
        <div class="col-md-6 col-lg-4 mb-3">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@course.CourseNumber</h5>
                    <h6 class="card-subtitle mb-2 text-muted">@course.Title</h6>
                    <p class="card-text">@course.Description[..Math.Min(course.Description.Length, 120)]…</p>
                    <span class="badge bg-secondary mb-2">@course.Credits credits</span>
                </div>
                <div class="card-footer">
                    <a href="courses/@course.Id" class="btn btn-primary btn-sm">View Details</a>
                </div>
            </div>
        </div>
    }
</div>

<h2>Departments</h2>
<div class="row">
    @foreach (var dept in departments)
    {
        <div class="col-md-6 col-lg-4 mb-3">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@dept.Abbreviation — @dept.Name</h5>
                    <p class="card-text">@dept.Description</p>
                </div>
                <div class="card-footer">
                    <a href="courses?department=@dept.Id" class="btn btn-outline-primary btn-sm">Browse Courses</a>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private List<Course> featuredCourses = new();
    private List<Department> departments = new();

    protected override void OnInitialized()
    {
        featuredCourses = Catalog.GetFeaturedCourses();
        departments = Catalog.GetDepartments();
    }
}

toolArgs.file_text:
@page "/courses/{CourseId}"
@using CourseCatalog.Models
@using CourseCatalog.Services
@inject CatalogService Catalog

<PageTitle>@(course?.Title ?? "Course") — Course Catalog</PageTitle>

@if (course is null)
{
    <div class="alert alert-warning">Course not found.</div>
    <a href="courses" class="btn btn-outline-primary">Back to Catalog</a>
}
else
{
    var dept = Catalog.GetDepartment(course.DepartmentId);

    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="courses">Catalog</a></li>
            @if (dept is not null)
            {
                <li class="breadcrumb-item"><a href="courses?department=@dept.Id">@dept.Name</a></li>
            }
            <li class="breadcrumb-item active" aria-current="page">@course.CourseNumber</li>
        </ol>
    </nav>

    <h1>@course.CourseNumber — @course.Title</h1>

    <div class="row mt-4">
        <div class="col-md-8">
            <h4>Description</h4>
            <p>@course.Description</p>

            <h4 class="mt-4">Schedule</h4>
            <p><span class="bi bi-clock" aria-hidden="true"></span> @course.Schedule</p>

            <h4 class="mt-4">Instructor</h4>
            <p><strong>@course.InstructorName</strong></p>
            <p>@course.InstructorBio</p>
        </div>

        <div class="col-md-4">
            <div class="card">
                <div class="card-body">
                    <h5 class="card-title">Course Info</h5>
                    <ul class="list-unstyled">
                        <li><strong>Credits:</strong> @course.Credits</li>
                        <li><strong>Department:</strong> @dept?.Name</li>
                        <li><strong>Course Number:</strong> @course.CourseNumber</li>
                    </ul>
                    <a href="enroll?courseId=@course.Id" class="btn btn-primary w-100">Enroll in this Course</a>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter]
    public string CourseId { get; set; } = string.Empty;

    private Course? course;

    protected override void OnInitialized()
    {
        course = Catalog.GetCourse(CourseId);
    }
}

@page "/enroll"
@using CourseCatalog.Models
@using CourseCatalog.Services
@using Microsoft.AspNetCore.Components.Forms
@inject CatalogService Catalog

<PageTitle>Enroll — University Course Catalog</PageTitle>

<h1>Enrollment Request</h1>
<p>Submit your enrollment request below. You will receive confirmation via your university email.</p>

@if (submitted)
{
    var selectedCourse = Catalog.GetCourse(model.CourseId);
    <div class="alert alert-success">
        <h4 class="alert-heading">Request Submitted!</h4>
        <p>Thank you, <strong>@model.FullName</strong> (ID: @model.StudentId).</p>
        <p>Your enrollment request for <strong>@selectedCourse?.CourseNumber — @selectedCourse?.Title</strong> has been received.</p>
        <hr />
        <a href="enroll" data-enhance-nav="false" class="btn btn-outline-success">Submit Another Request</a>
        <a href="courses" class="btn btn-outline-primary ms-2">Back to Catalog</a>
    </div>
}
else
{
    <EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="enrollment" Enhance>
        <DataAnnotationsValidator />
        <AntiforgeryToken />
        <ValidationSummary class="text-danger" />

        <div class="mb-3" style="max-width: 500px;">
            <label for="fullName" class="form-label">Full Name</label>
            <InputText id="fullName" class="form-control" @bind-Value="model.FullName" />
            <ValidationMessage For="() => model.FullName" class="text-danger" />
        </div>

        <div class="mb-3" style="max-width: 500px;">
            <label for="studentId" class="form-label">Student ID</label>
            <InputText id="studentId" class="form-control" @bind-Value="model.StudentId" />
            <ValidationMessage For="() => model.StudentId" class="text-danger" />
        </div>

        <div class="mb-3" style="max-width: 500px;">
            <label for="courseId" class="form-label">Course</label>
            <InputSelect id="courseId" class="form-select" @bind-Value="model.CourseId">
                <option value="">— Select a course —</option>
                @foreach (var course in courses)
                {
                    <option value="@course.Id">@course.CourseNumber — @course.Title (@course.Credits cr)</option>
                }
            </InputSelect>
            <ValidationMessage For="() => model.CourseId" class="text-danger" />
        </div>

        <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
        <a href="courses" class="btn btn-outline-secondary ms-2">Cancel</a>
    </EditForm>
}

@code {
    [SupplyParameterFromForm]
    private EnrollmentRequest model { get; set; } = new();

    [SupplyParameterFromQuery(Name = "courseId")]
    public string? PreselectedCourseId { get; set; }

    private List<Course> courses = new();
    private bool submitted;

    protected override void OnInitialized()
    {
        courses = Catalog.GetCourses().OrderBy(c => c.CourseNumber).ToList();

        if (!string.IsNullOrEmpty(PreselectedCourseId) && string.IsNullOrEmpty(model.CourseId))
        {
            model.CourseId = PreselectedCourseId;
        }
    }

    private void HandleSubmit()
    {
        submitted = true;
    }
}

